-- site_sections 테이블 생성 (Supabase SQL Editor에서 실행)
-- 에러: Could not find the table 'public.site_sections' 해결용

CREATE TABLE IF NOT EXISTS site_sections (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  section_key TEXT UNIQUE NOT NULL,
  content JSONB NOT NULL DEFAULT '{}',
  updated_at TIMESTAMPTZ DEFAULT now()
);

ALTER TABLE site_sections ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "site_sections_anon_read" ON site_sections;
CREATE POLICY "site_sections_anon_read" ON site_sections FOR SELECT USING (true);

-- service_role로 쓰기 (admin API) - RLS 우회됨. 추가 정책 불필요.

